$dec = { param($a) if ($a) { ([Text.Encoding]::ASCII.GetString($a)).Trim([char]0) } else { $null } }
Get-CimInstance -Namespace root\wmi -ClassName WMIMonitorID -ErrorAction Stop | ForEach-Object {
    [pscustomobject]@{
        Manufacturer      = & $dec $_.ManufacturerName
        Model             = & $dec $_.UserFriendlyName
        SerialNumber      = & $dec $_.SerialNumberID
        WeekOfManufacture = $_.WeekOfManufacture
        YearOfManufacture = $_.YearOfManufacture
    }
}

$static = Get-CimInstance -Namespace root\wmi -ClassName BatteryStaticData -ErrorAction SilentlyContinue | Select-Object -First 1
$full = Get-CimInstance -Namespace root\wmi -ClassName BatteryFullChargedCapacity -ErrorAction SilentlyContinue | Select-Object -First 1
if ($static -or $full) {
    $designed = $static.DesignedCapacity
    $charged = $full.FullChargedCapacity
    [pscustomobject]@{
        DesignedCapacity    = $designed
        FullChargedCapacity = $charged
        HealthPercent       = if ($designed -and $charged) { [math]::Round(($charged / $designed) * 100, 1) } else { $null }
    }
}

$types = @{ 3 = 'Desktop'; 4 = 'LowProfileDesktop'; 5 = 'PizzaBox'; 6 = 'MiniTower'; 7 = 'Tower'; 8 = 'Portable'; 9 = 'Laptop'; 10 = 'Notebook'; 11 = 'HandHeld'; 12 = 'DockingStation'; 13 = 'AllInOne'; 14 = 'SubNotebook'; 15 = 'SpaceSaving'; 16 = 'LunchBox'; 17 = 'MainSystemChassis'; 18 = 'ExpansionChassis'; 21 = 'PeripheralChassis'; 22 = 'StorageChassis'; 23 = 'RackMountChassis'; 24 = 'SealedCasePC'; 30 = 'Tablet'; 31 = 'Convertible'; 32 = 'Detachable' }
Get-CimInstance -ClassName Win32_SystemEnclosure -ErrorAction Stop | ForEach-Object {
    $tag = $_.SMBIOSAssetTag
    foreach ($code in $_.ChassisTypes) {
        [pscustomobject]@{
            ChassisTypeCode = [int]$code
            ChassisType     = $types[[int]$code]
            AssetTag        = $tag
        }
    }
}
